// Funciones de inicialización de fechas
function setInitialDates() {
    const today = new Date();
    // Iniciar desde hoy
    const firstDay = new Date(today.getFullYear(), today.getMonth(), today.getDate());
    // Fin a 30 días
    const lastDay = new Date(today.getFullYear(), today.getMonth(), today.getDate() + 30);
    
    const formatDate = (date) => {
        let d = new Date(date);
        let month = '' + (d.getMonth() + 1);
        let day = '' + d.getDate();
        let year = d.getFullYear();

        if (month.length < 2) month = '0' + month;
        if (day.length < 2) day = '0' + day;

        return [year, month, day].join('-');
    };
    
    document.getElementById('fechaInicio').value = formatDate(firstDay);
    document.getElementById('fechaFin').value = formatDate(lastDay);
}
setInitialDates();

excelUpload.addEventListener('change', handleExcelUpload);
bgUpload.addEventListener('change', handleBgUpload);

const settingsInputs = document.querySelectorAll('input, select');
settingsInputs.forEach(input => {
    input.addEventListener('input', () => {
        if (Object.keys(parsedCourses).length > 0 && bgImageElement.src) {
            const firstCourseId = Object.keys(parsedCourses)[0];
            drawPreview(parsedCourses[firstCourseId]);
        }
    });
});

function checkReady() {
    if (excelData && bgImage) {
        generateBtn.disabled = false;
        generateBtn.textContent = "Generar Todos los Cronogramas";
        
        groupDataByCourse();
        if (Object.keys(parsedCourses).length > 0) {
            const firstCourseId = Object.keys(parsedCourses)[0];
            drawPreview(parsedCourses[firstCourseId]);
        } else {
            alert('No se encontraron cursos válidos en el Excel.');
        }
    }
}

function handleExcelUpload(e) {
    const file = e.target.files[0];
    if (!file) return;
    
    document.getElementById('excelFileName').textContent = file.name;
    
    const reader = new FileReader();
    reader.onload = function(e) {
        const data = new Uint8Array(e.target.result);
        try {
            const workbook = XLSX.read(data, {type: 'array'});
            const firstSheetName = workbook.SheetNames[0];
            const worksheet = workbook.Sheets[firstSheetName];
            
            excelData = XLSX.utils.sheet_to_json(worksheet, {raw: false});
            console.log("Datos cargados:", excelData);
            checkReady();
        } catch (err) {
            alert("Error al leer el archivo Excel. Asegúrate de que es un archivo válido (.xlsx o .xls)");
            console.error(err);
        }
    };
    reader.readAsArrayBuffer(file);
}

function handleBgUpload(e) {
    const file = e.target.files[0];
    if (!file) return;
    
    document.getElementById('bgFileName').textContent = file.name;
    bgImage = file;
    
    const reader = new FileReader();
    reader.onload = function(event) {
        bgImageElement.onload = () => {
            checkReady();
        };
        bgImageElement.src = event.target.result;
    };
    reader.readAsDataURL(file);
}

function groupDataByCourse() {
    parsedCourses = {};
    
    excelData.forEach(row => {
        const keys = Object.keys(row);
        
        const findKey = (searchArr) => keys.find(k => searchArr.some(s => k.toLowerCase().includes(s)));
        
        let imgNameKey = findKey(['img-name', 'img name']);
        let carreraKey = findKey(['carrera']);
        let cursoKey = findKey(['curso']);
        let docenteKey = findKey(['docente', 'profesor']);
        let aulaKey = findKey(['aula']);
        let zoomVKey = findKey(['zoom virtuales', 'zoom virtual']);
        let pracPKey = findKey(['prácticas presenciales', 'practicas presenciales']);
        let sede1Key = findKey(['sede1', 'sede 1']);
        let sede2Key = findKey(['sede2', 'sede 2']);
        let dir1Key = keys.find(k => k.toLowerCase() === 'dirección' || k.toLowerCase() === 'direccion');
        let dir2Key = keys.find(k => k.toLowerCase() === 'dirección2' || k.toLowerCase() === 'direccion2');
        if(!dir2Key) dir2Key = keys.find(k => k.toLowerCase().includes('dirección 2') || k.toLowerCase().includes('direccion 2'));
        if(!dir1Key) dir1Key = findKey(['dirección', 'direccion']);
        if (dir1Key && dir2Key && dir1Key === dir2Key) dir1Key = keys.find(k => k.toLowerCase() === 'dirección' || k.toLowerCase() === 'direccion');

        let defaultId = `schedule_${Math.random()}`;
        let id = imgNameKey && row[imgNameKey] ? row[imgNameKey] : (cursoKey && row[cursoKey] ? row[cursoKey] : defaultId);
        
        if (!parsedCourses[id]) {
            parsedCourses[id] = {
                id: id,
                imgName: imgNameKey ? row[imgNameKey] : '',
                carrera: carreraKey ? row[carreraKey] : '',
                curso: cursoKey ? row[cursoKey] : '',
                docente: docenteKey ? row[docenteKey] : '',
                aula: aulaKey ? row[aulaKey] : '',
                zoomV: zoomVKey ? row[zoomVKey] : '',
                pracP: pracPKey ? row[pracPKey] : '',
                sede1: sede1Key ? row[sede1Key] : '',
                sede2: sede2Key ? row[sede2Key] : '',
                dir1: dir1Key ? row[dir1Key] : '',
                dir2: dir2Key ? row[dir2Key] : '',
                dias: []
            };
        }
        
        keys.forEach(k => {
            const match = k.match(/^img(\d+)$/i);
            if (match) {
                const diaNumero = parseInt(match[1]);
                let actVal = row[k];
                const actividad = actVal ? actVal.toString().trim() : '';
                
                if (actividad !== '') {
                    parsedCourses[id].dias.push({
                        dia: diaNumero,
                        actividad: actividad
                    });
                }
            }
        });
    });
}

function wrapText(ctx, text, x, y, maxWidth, lineHeight, strokeProps = null) {
    if (!text) return { w: 0, h: 0 };
    const paragraphs = String(text).split('\n');
    let line = '';
    let startY = y;
    let actualMaxWidth = 0;
    
    const drawLine = (textStr, posX, posY) => {
        if (strokeProps && strokeProps.enabled) {
            ctx.lineJoin = 'round';
            ctx.miterLimit = 2;
            ctx.strokeStyle = strokeProps.color;
            ctx.lineWidth = strokeProps.width;
            ctx.strokeText(textStr, posX, posY);
        }
        ctx.fillText(textStr, posX, posY);
        actualMaxWidth = Math.max(actualMaxWidth, ctx.measureText(textStr).width);
    };

    paragraphs.forEach((paragraph, pIdx) => {
        const words = paragraph.split(' ');
        for(let n = 0; n < words.length; n++) {
            const testLine = line + words[n] + ' ';
            const metrics = ctx.measureText(testLine);
            const testWidth = metrics.width;
            if (testWidth > maxWidth && n > 0) {
                drawLine(line, x, y);
                line = words[n] + ' ';
                y += lineHeight;
            } else {
                line = testLine;
            }
        }
        drawLine(line, x, y);
        line = '';
        if (pIdx < paragraphs.length - 1) y += lineHeight;
    });
    return { w: actualMaxWidth, h: (y - startY) + lineHeight };
}

let generatedImages = [];

function drawCourseOnCanvas(canvasToDraw, ctxToDraw, course) {
    canvasToDraw.width = bgImageElement.width;
    canvasToDraw.height = bgImageElement.height;
    
    ctxToDraw.drawImage(bgImageElement, 0, 0);
    
    if (canvasToDraw === previewCanvas) {
        interactiveFields = [];
    }

    const defaultColor = document.getElementById('textColor') ? document.getElementById('textColor').value : '#ffffff';
    ctxToDraw.fillStyle = defaultColor;
    ctxToDraw.textBaseline = 'top';
    
    function drawField(idPrefix, value, boldClass, placeholderText) {
        let textToDraw = value;
        let isPlaceholder = false;
        if (!value || value.toString().trim() === '') {
            if (canvasToDraw === previewCanvas && placeholderText) {
                textToDraw = `[${placeholderText}]`;
                isPlaceholder = true;
            } else {
                return;
            }
        }
        const xEl = document.getElementById(idPrefix + 'X');
        if (!xEl) return;
        const x = parseInt(xEl.value);
        const y = parseInt(document.getElementById(idPrefix + 'Y').value);
        const size = parseInt(document.getElementById(idPrefix + 'Size').value);
        const maxW = parseInt(document.getElementById(idPrefix + 'W').value);
        const colorEl = document.getElementById(idPrefix + 'C');
        const color = colorEl ? colorEl.value : defaultColor;
        
        const strokeWEl = document.getElementById(idPrefix + 'StrokeW');
        const strokeC = document.getElementById(idPrefix + 'StrokeC');
        const strokeW = strokeWEl ? parseInt(strokeWEl.value) : 0;
        const currentStrokeProps = {
            enabled: strokeW > 0,
            color: strokeC ? strokeC.value : '#000000',
            width: strokeW
        };
        
        ctxToDraw.fillStyle = color;
        ctxToDraw.font = `${boldClass} ${size}px Inter, sans-serif`; 
        
        if (isPlaceholder) {
            ctxToDraw.globalAlpha = 0.5;
        }
        
        const dims = wrapText(ctxToDraw, textToDraw, x, y, maxW, size * 1.2, currentStrokeProps);
        
        if (isPlaceholder) {
            ctxToDraw.globalAlpha = 1.0;
        }
        
        if (canvasToDraw === previewCanvas) {
            interactiveFields.push({
                idPrefix, x, y, maxW,
                w: dims.w, h: dims.h, size
            });
            
            if (activeField && activeField.idPrefix === idPrefix) {
                ctxToDraw.strokeStyle = '#3b82f6';
                ctxToDraw.lineWidth = 2;
                ctxToDraw.setLineDash([5, 5]);
                ctxToDraw.strokeRect(x - 5, y - 5, maxW + 10, dims.h + 10);
                ctxToDraw.setLineDash([]);
                
                ctxToDraw.fillStyle = '#3b82f6';
                ctxToDraw.beginPath();
                ctxToDraw.arc(x + maxW, y + (dims.h/2), 8, 0, Math.PI * 2);
                ctxToDraw.fill();
            }
        }
        ctxToDraw.fillStyle = defaultColor;
    }
    
    const globalCarrera = document.getElementById('carreraGlobal').value;
    const finalCarrera = globalCarrera !== 'EXCEL' ? globalCarrera : course.carrera;
    
    drawField('carrera', finalCarrera, 'bold', 'Carrera');
    drawField('curso', course.curso, 'bold', 'Curso');
    drawField('docente', course.docente, 'bold', 'Docente');
    drawField('aula', course.aula, 'bold', 'Aula');
    drawField('zoomV', course.zoomV, 'bold', 'Zoom Virt.');
    drawField('pracP', course.pracP, 'bold', 'Prac. Pres.');
    drawField('sede1', course.sede1, 'bold', 'Sede 1');
    
    let sede2Text = course.sede2;
    if (course.sede2 && course.sede2.trim() !== '') {
        const validGpsActivity = course.dias.find(d => {
            const act = d.actividad.toLowerCase();
            const upperAct = d.actividad.toUpperCase();
            return !act.includes('zoom') && !act.includes('feriado') && !act.includes('exam') && !upperAct.includes('SOP');
        });
        
        if (validGpsActivity) {
            const gpsStr = validGpsActivity.actividad.toString().trim();
            if (gpsStr !== '') {
                sede2Text = "OBS: Considerar " + gpsStr + " como local de " + course.sede2;
            }
        }
    }
    drawField('sede2', sede2Text, 'bold', 'Sede 2');
    
    drawField('dir1', course.dir1, 'bold', 'Dirección');
    drawField('dir2', course.dir2, 'bold', 'Dirección 2');
    
    const gridX = parseInt(document.getElementById('gridX').value);
    const gridY = parseInt(document.getElementById('gridY').value);
    const cellW = parseInt(document.getElementById('cellW').value);
    const cellH = parseInt(document.getElementById('cellH').value);
    const iconSize = parseInt(document.getElementById('iconSize').value);
    const drawNumbers = document.getElementById('drawNumbers').checked;
    const gridColorEl = document.getElementById('gridColor');
    const gridColor = gridColorEl ? gridColorEl.value : defaultColor;
    const gridTextColorEl = document.getElementById('gridTextColor');
    const gridTextColor = gridTextColorEl ? gridTextColorEl.value : defaultColor;
    
    const gridTextStrokeWEl = document.getElementById('gridTextStrokeW');
    const gridTextStrokeC = document.getElementById('gridTextStrokeC');
    const gridTextStrokeWidth = gridTextStrokeWEl ? parseInt(gridTextStrokeWEl.value) : 0;
    const gridStrokeProps = {
        enabled: gridTextStrokeWidth > 0,
        color: gridTextStrokeC ? gridTextStrokeC.value : '#000000',
        width: gridTextStrokeWidth
    };
    
    const feriadoColorEl = document.getElementById('feriadoColor');
    const feriadoColor = feriadoColorEl ? feriadoColorEl.value : '#ff0000';
    const gridTextSizeEl = document.getElementById('gridTextSize');
    const gridTextSize = gridTextSizeEl ? parseInt(gridTextSizeEl.value) : 20;
    const gridNumberSizeEl = document.getElementById('gridNumberSize');
    const gridNumberSize = gridNumberSizeEl ? parseInt(gridNumberSizeEl.value) : Math.floor(cellH/3.5);
    
    const fInicioStr = document.getElementById('fechaInicio').value;
    const fFinStr = document.getElementById('fechaFin').value;
    
    if (!fInicioStr || !fFinStr) return;
    
    const fInicio = new Date(fInicioStr + 'T12:00:00');
    const fFin = new Date(fFinStr + 'T12:00:00');
    
    if (fFin < fInicio) return;
    
    let startWeekday = fInicio.getDay();
    startWeekday = startWeekday === 0 ? 6 : startWeekday - 1;
    
    let currentDate = new Date(fInicio);
    let dayIndex = 0;
    
    while(currentDate <= fFin) {
        const offset = dayIndex + startWeekday;
        const col = offset % 7;
        const row = Math.floor(offset / 7);
        
        const cellLeft = gridX + (col * cellW);
        const cellTop = gridY + (row * cellH);
        
        const dayNum = currentDate.getDate();
        
        if (drawNumbers) {
            ctxToDraw.fillStyle = gridColor;
            ctxToDraw.font = `bold ${gridNumberSize}px Inter, sans-serif`;
            if (gridStrokeProps.enabled) {
                ctxToDraw.lineJoin = 'round';
                ctxToDraw.miterLimit = 2;
                ctxToDraw.strokeStyle = gridStrokeProps.color;
                ctxToDraw.lineWidth = gridStrokeProps.width;
                ctxToDraw.strokeText(dayNum.toString(), cellLeft + 8, cellTop + 8);
            }
            ctxToDraw.fillText(dayNum.toString(), cellLeft + 8, cellTop + 8);
        }
        
        const matchingActivities = course.dias.filter(d => d.dia === dayNum);
        
        if (matchingActivities.length > 0) {
            const item = matchingActivities[0];
            let actStr = item.actividad.toLowerCase();
            let actOriginal = item.actividad;
            let iconToDraw = null;
            let drawText = true;
            let textYoffsetMultiplier = 0.05;
            let currentTextColor = gridTextColor;
            
            if (actStr.includes('feriado')) {
                iconToDraw = null;
                actOriginal = "FERIADO";
                currentTextColor = feriadoColor;
                textYoffsetMultiplier = -0.5;
            } else if (actStr.includes('exam.parcial') || actStr.includes('exam.final')) {
                iconToDraw = loadedIcons['examen'];
                actOriginal = actStr.includes('parcial') ? "EXAMEN\nPARCIAL" : "EXAMEN\nFINAL";
            } else if (actStr.includes('zoom')) {
                iconToDraw = loadedIcons['zoom'];
                drawText = false;
            } else {
                iconToDraw = loadedIcons['gps'];
            }
            
            let posY = cellTop + 12; 
            let posX = cellLeft + 33; 
            
            if (iconToDraw) {
                ctxToDraw.drawImage(iconToDraw, posX, posY, iconSize, iconSize);
            }
            
            if (drawText) {
                ctxToDraw.font = `bold ${gridTextSize}px Inter, sans-serif`;
                ctxToDraw.textAlign = 'center';
                ctxToDraw.fillStyle = currentTextColor;
                let textPosY = iconToDraw ? posY + iconSize + 2 : cellTop + (cellH/2);
                wrapText(ctxToDraw, actOriginal, cellLeft + (cellW/2), textPosY, cellW - 10, Math.floor(gridTextSize * 1.2), gridStrokeProps);
                ctxToDraw.textAlign = 'left'; 
            }
        }
        
        currentDate.setDate(currentDate.getDate() + 1);
        dayIndex++;
    }

    if (canvasToDraw === previewCanvas) {
        let gridRows = dayIndex > 0 ? Math.ceil((dayIndex + startWeekday) / 7) : 5;
        let totalGridW = 7 * cellW;
        let totalGridH = gridRows * cellH;
        
        interactiveFields.push({
            idPrefix: 'grid', x: gridX, y: gridY,
            w: totalGridW, h: totalGridH, maxW: totalGridW,
            type: 'grid', gridRows: gridRows,
            cellW: cellW, cellH: cellH
        });

        if (activeField && activeField.idPrefix === 'grid') {
            ctxToDraw.strokeStyle = '#3b82f6';
            ctxToDraw.lineWidth = 2;
            ctxToDraw.setLineDash([5, 5]);
            ctxToDraw.strokeRect(gridX, gridY, totalGridW, totalGridH);
            ctxToDraw.setLineDash([]);

            ctxToDraw.fillStyle = '#3b82f6';
            ctxToDraw.beginPath();
            ctxToDraw.arc(gridX + totalGridW, gridY + (totalGridH / 2), 8, 0, Math.PI * 2);
            ctxToDraw.fill();

            ctxToDraw.beginPath();
            ctxToDraw.arc(gridX + (totalGridW / 2), gridY + totalGridH, 8, 0, Math.PI * 2);
            ctxToDraw.fill();
        }
    }
}

function drawPreview(course) {
    placeholder.style.display = 'none';
    previewCanvas.style.display = 'block';
    
    drawCourseOnCanvas(previewCanvas, ctx, course);
}

generateBtn.addEventListener('click', () => {
    const gallery = document.getElementById('gallery');
    gallery.innerHTML = '';
    
    document.getElementById('resultsPanel').style.display = 'block';
    document.getElementById('resultsPanel').scrollIntoView({ behavior: 'smooth' });
    generatedImages = [];
    
    Object.values(parsedCourses).forEach(course => {
        const tempCanvas = document.createElement('canvas');
        const tempCtx = tempCanvas.getContext('2d');
        
        drawCourseOnCanvas(tempCanvas, tempCtx, course);
        
        const dataUrl = tempCanvas.toDataURL('image/png');
        const cName = course.imgName || course.curso || course.id;
        generatedImages.push({ name: cName, dataUrl: dataUrl });
        
        const item = document.createElement('div');
        item.className = 'gallery-item';
        
        const img = document.createElement('img');
        img.src = dataUrl;
        
        const title = document.createElement('h3');
        title.textContent = cName;
        
        const downloadBtn = document.createElement('a');
        downloadBtn.href = dataUrl;
        downloadBtn.download = `${cName}.png`;
        downloadBtn.className = 'secondary-btn';
        downloadBtn.style.display = 'inline-block';
        downloadBtn.style.textDecoration = 'none';
        downloadBtn.textContent = 'Descargar PNG';
        
        item.appendChild(img);
        item.appendChild(title);
        item.appendChild(downloadBtn);
        
        gallery.appendChild(item);
    });
});

document.getElementById('downloadAllBtn').addEventListener('click', () => {
    if (generatedImages.length === 0) return;
    const btn = document.getElementById('downloadAllBtn');
    const originalText = btn.textContent;
    btn.textContent = 'Generando ZIP...';
    btn.disabled = true;

    const zip = new JSZip();
    
    generatedImages.forEach(img => {
        const base64Data = img.dataUrl.replace(/^data:image\/(png|jpeg);base64,/, "");
        zip.file(`${img.name.replace(/[/\\?%*:|"<>]/g, '-')}.webp`, base64Data, {base64: true});
    });
    
    zip.generateAsync({type:"blob"}).then(function(content) {
        saveAs(content, "Cronogramas.zip");
        btn.textContent = originalText;
        btn.disabled = false;
    });
});

// --- Interactive Canvas Drag & Drop ---
function getMousePos(canvas, evt) {
    const rect = canvas.getBoundingClientRect();
    const scaleX = canvas.width / rect.width;
    const scaleY = canvas.height / rect.height;
    return {
      x: (evt.clientX - rect.left) * scaleX,
      y: (evt.clientY - rect.top) * scaleY
    };
}

previewCanvas.addEventListener('mousedown', (e) => {
   const pos = getMousePos(previewCanvas, e);
   for (let i = interactiveFields.length - 1; i >= 0; i--) {
       const f = interactiveFields[i];
       if (f.type === 'grid') {
           if (Math.abs(pos.x - (f.x + f.w)) < 15 && Math.abs(pos.y - (f.y + f.h/2)) < 15) {
               activeField = f;
               isDraggingWidth = true;
               dragOffsetX = 'gridW';
               return;
           }
           if (Math.abs(pos.x - (f.x + f.w/2)) < 15 && Math.abs(pos.y - (f.y + f.h)) < 15) {
               activeField = f;
               isDraggingWidth = true;
               dragOffsetX = 'gridH';
               return;
           }
           if (pos.x >= f.x - 5 && pos.x <= f.x + f.w + 5 && pos.y >= f.y - 5 && pos.y <= f.y + f.h + 5) {
               activeField = f;
               isDraggingPos = true;
               dragOffsetX = pos.x - f.x;
               dragOffsetY = pos.y - f.y;
               return;
           }
       } else {
           if (Math.abs(pos.x - (f.x + f.maxW)) < 15 && pos.y >= f.y - 10 && pos.y <= f.y + f.h + 10) {
               activeField = f;
               isDraggingWidth = true;
               dragOffsetX = 'fieldW';
               return;
           }
           if (pos.x >= f.x - 5 && pos.x <= f.x + f.maxW + 5 && pos.y >= f.y - 5 && pos.y <= f.y + f.h + 5) {
               activeField = f;
               isDraggingPos = true;
               dragOffsetX = pos.x - f.x;
               dragOffsetY = pos.y - f.y;
               return;
           }
       }
   }
   activeField = null;
   const firstId = Object.keys(parsedCourses)[0];
   if (firstId) drawPreview(parsedCourses[firstId]);
});

previewCanvas.addEventListener('mousemove', (e) => {
   const pos = getMousePos(previewCanvas, e);
   if (isDraggingPos && activeField) {
       let newX = Math.round(pos.x - dragOffsetX);
       let newY = Math.round(pos.y - dragOffsetY);
       if (activeField.type === 'grid') {
           document.getElementById('gridX').value = newX;
           document.getElementById('gridY').value = newY;
       } else {
           document.getElementById(activeField.idPrefix + 'X').value = newX;
           document.getElementById(activeField.idPrefix + 'Y').value = newY;
       }
       const firstId = Object.keys(parsedCourses)[0];
       if (firstId) drawPreview(parsedCourses[firstId]);
   } else if (isDraggingWidth && activeField) {
       if (activeField.type === 'grid') {
           if (dragOffsetX === 'gridW') {
               let newTotalW = Math.round(pos.x - activeField.x);
               let newCellW = Math.max(20, Math.round(newTotalW / 7));
               document.getElementById('cellW').value = newCellW;
           } else if (dragOffsetX === 'gridH') {
               let newTotalH = Math.round(pos.y - activeField.y);
               let newCellH = Math.max(20, Math.round(newTotalH / activeField.gridRows));
               document.getElementById('cellH').value = newCellH;
           }
       } else {
           let newW = Math.round(pos.x - activeField.x);
           if (newW < 20) newW = 20;
           document.getElementById(activeField.idPrefix + 'W').value = newW;
       }
       const firstId = Object.keys(parsedCourses)[0];
       if (firstId) drawPreview(parsedCourses[firstId]);
   } else {
       let overHandle = false;
       let overField = false;
       let handleType = ''; 
       for (let i = interactiveFields.length - 1; i >= 0; i--) {
           const f = interactiveFields[i];
           if (f.type === 'grid') {
               if (Math.abs(pos.x - (f.x + f.w)) < 15 && Math.abs(pos.y - (f.y + f.h/2)) < 15) {
                   overHandle = true; handleType = 'ew'; break;
               }
               if (Math.abs(pos.x - (f.x + f.w/2)) < 15 && Math.abs(pos.y - (f.y + f.h)) < 15) {
                   overHandle = true; handleType = 'ns'; break;
               }
               if (pos.x >= f.x - 5 && pos.x <= f.x + f.w + 5 && pos.y >= f.y - 5 && pos.y <= f.y + f.h + 5) {
                   overField = true; break;
               }
           } else {
               if (Math.abs(pos.x - (f.x + f.maxW)) < 15 && pos.y >= f.y - 10 && pos.y <= f.y + f.h + 10) {
                   overHandle = true; handleType = 'ew'; break;
               }
               if (pos.x >= f.x - 5 && pos.x <= f.x + f.maxW + 5 && pos.y >= f.y - 5 && pos.y <= f.y + f.h + 5) {
                   overField = true; break;
               }
           }
       }
       if (overHandle) {
           previewCanvas.style.cursor = handleType === 'ns' ? 'ns-resize' : 'ew-resize';
       }
       else if (overField) previewCanvas.style.cursor = 'move';
       else previewCanvas.style.cursor = 'default';
   }
});

previewCanvas.addEventListener('mouseup', () => {
    isDraggingPos = false;
    isDraggingWidth = false;
});
previewCanvas.addEventListener('mouseleave', () => {
    isDraggingPos = false;
    isDraggingWidth = false;
});
